import{_ as a,o as t,c as d,a4 as b}from"./chunks/framework.Cqne-ChA.js";const m=JSON.parse('{"title":"","description":"","frontmatter":{},"headers":[],"relativePath":"reference/zopen-publish.md","filePath":"reference/zopen-publish.md","lastUpdated":1776850763000}'),p={name:"reference/zopen-publish.md"};function i(r,e,n,c,l,o){return t(),d("div",null,[...e[0]||(e[0]=[b('<div class="man-page-content" data-v-bdeec81e><h1 align="center" data-v-bdeec81e>ZOPEN-PUBLISH</h1><h2 data-v-bdeec81e>NAME <a name="NAME" data-v-bdeec81e></a></h2><p style="margin-left:11%;margin-top:1em;" data-v-bdeec81e>zopen-publish − manual page for zopen-publish 0.8.4</p><h2 data-v-bdeec81e>SYNOPSIS <a name="SYNOPSIS" data-v-bdeec81e></a></h2><p style="margin-left:11%;margin-top:1em;" data-v-bdeec81e><b data-v-bdeec81e>zopen-publish</b> [<i data-v-bdeec81e>OPTION</i>] <i data-v-bdeec81e>-p PAX_FILE -m METADATA_FILE -g TAG</i></p><h2 data-v-bdeec81e>DESCRIPTION <a name="DESCRIPTION" data-v-bdeec81e></a></h2><p style="margin-left:11%;margin-top:1em;" data-v-bdeec81e>zopen−publish − Publish zopen package release to GitHub.</p><h2 data-v-bdeec81e>OPTIONS <a name="OPTIONS" data-v-bdeec81e></a></h2><p style="margin-left:11%;margin-top:1em;" data-v-bdeec81e><b data-v-bdeec81e>−h</b>, <b data-v-bdeec81e>−−help</b></p><p style="margin-left:22%;" data-v-bdeec81e>print this help</p><p style="margin-left:11%;" data-v-bdeec81e><b data-v-bdeec81e>−v</b>, <b data-v-bdeec81e>−−verbose</b></p><p style="margin-left:22%;" data-v-bdeec81e>run in verbose mode.</p><p style="margin-left:11%;" data-v-bdeec81e><b data-v-bdeec81e>−f</b>, <b data-v-bdeec81e>−−force</b></p><p style="margin-left:22%;" data-v-bdeec81e>Force overwrite release if tag exists.</p><p style="margin-left:11%;" data-v-bdeec81e><b data-v-bdeec81e>−p</b>, <b data-v-bdeec81e>−−pax−file</b> PAX_FILE</p><p style="margin-left:22%;" data-v-bdeec81e>Path to the pax.Z file (required)</p><p style="margin-left:11%;" data-v-bdeec81e><b data-v-bdeec81e>−m</b>, <b data-v-bdeec81e>−−metadata−file</b> METADATA_FILE</p><p style="margin-left:22%;" data-v-bdeec81e>Path to the metadata.json file (required)</p><p style="margin-left:11%;" data-v-bdeec81e><b data-v-bdeec81e>−g</b>, <b data-v-bdeec81e>−−tag</b> TAG</p><p style="margin-left:22%;" data-v-bdeec81e>Tag name for the release (required) e.g., DEV_mypackage_12345</p><p style="margin-left:11%;" data-v-bdeec81e><b data-v-bdeec81e>−r</b>, <b data-v-bdeec81e>−−repo</b> REPO_URL</p><p style="margin-left:22%;" data-v-bdeec81e>GitHub repository URL (optional, overrides metadata.json) e.g., https://github.com/zopencommunity/xzport.git</p><p style="margin-left:11%;" data-v-bdeec81e><b data-v-bdeec81e>−d</b>, <b data-v-bdeec81e>−−description</b> TEXT</p><p style="margin-left:22%;" data-v-bdeec81e>Description for the GitHub release (optional, from metadata.json ’summary’ if omitted)</p><p style="margin-left:11%;" data-v-bdeec81e><b data-v-bdeec81e>−b</b>, <b data-v-bdeec81e>−−build−line</b> LINE</p><p style="margin-left:22%;" data-v-bdeec81e>Build line (DEV or STABLE) (optional, from metadata.json ’buildline’ if omitted)</p><p style="margin-left:11%;" data-v-bdeec81e><b data-v-bdeec81e>−t</b>, <b data-v-bdeec81e>−−github−token</b> TOKEN</p><p style="margin-left:22%;" data-v-bdeec81e>GitHub Personal Access Token (required, or set GITHUB_TOKEN env var)</p><p style="margin-left:11%;" data-v-bdeec81e><b data-v-bdeec81e>−o</b>, <b data-v-bdeec81e>−−github−org</b> ORG</p><p style="margin-left:22%;" data-v-bdeec81e>GitHub Organization (default: zopencommunity)</p><p style="margin-left:11%;" data-v-bdeec81e><b data-v-bdeec81e>−l</b>, <b data-v-bdeec81e>−−latest</b></p><p style="margin-left:22%;" data-v-bdeec81e>Mark release as ’Latest’ (not pre−release).</p><p style="margin-left:11%;" data-v-bdeec81e><b data-v-bdeec81e>−−version</b></p><p style="margin-left:22%;" data-v-bdeec81e>print version</p><p style="margin-left:11%;margin-top:1em;" data-v-bdeec81e><b data-v-bdeec81e>Environment GITHUB_TOKEN</b></p><p style="margin-left:22%;" data-v-bdeec81e>GitHub Personal Access Token (alternative to <b data-v-bdeec81e>−−github−token</b>)</p><p style="margin-left:11%;margin-top:1em;" data-v-bdeec81e><b data-v-bdeec81e>Example:</b></p><p style="margin-left:22%;" data-v-bdeec81e>zopen−publish <b data-v-bdeec81e>−f −p</b> install/mypackage.zos.pax.Z <b data-v-bdeec81e>−m</b> metadata.json <b data-v-bdeec81e>−g</b> DEV_mypackage_12345 <b data-v-bdeec81e>−t</b> &lt;your_github_token&gt; zopen−publish <b data-v-bdeec81e>−v −f −p</b> install/mypackage.zos.pax.Z <b data-v-bdeec81e>−m</b> metadata.json <b data-v-bdeec81e>−r</b> https://github.com/zopencommunity/override−repo.git <b data-v-bdeec81e>−d</b> &quot;My custom release description&quot; <b data-v-bdeec81e>−b</b> DEV <b data-v-bdeec81e>−g</b> REL−1.0.1 <b data-v-bdeec81e>−t</b> &lt;your_github_token&gt; <b data-v-bdeec81e>−l</b></p><p style="margin-left:11%;margin-top:1em;" data-v-bdeec81e>This is free software: you are free to change and redistribute it under the terms of the Apache License, Version 2.0. &lt;https://www.apache.org/licenses/LICENSE−2.0.html&gt; There is NO WARRANTY, to the extent permitted by law.</p><h2 data-v-bdeec81e>AUTHOR <a name="AUTHOR" data-v-bdeec81e></a></h2><p style="margin-left:11%;margin-top:1em;" data-v-bdeec81e>Written by contributors to the zopen community. &lt;https://github.com/zopencommunity/meta/graphs/contributors&gt;</p></div>',1)])])}const v=a(p,[["render",i],["__scopeId","data-v-bdeec81e"]]);export{m as __pageData,v as default};
